<script setup lang="ts">
import{computed,ref}from'vue';import{onLoad,onShow}from'@dcloudio/uni-app';import{medicalApi,type VisitSummary}from'../../api/medical';import{currentPatient}from'../../stores/session'
const records=ref<VisitSummary[]>([]),loading=ref(false)
const archivedCount=computed(()=>records.value.filter(item=>item.archiveStatus==='archived').length)
const diagnosisCount=computed(()=>records.value.filter(item=>item.diagnosis||item.preliminaryDiagnosis).length)
const tones=['blue','green','purple','orange']
async function load(){const patient=currentPatient.value;if(!patient)return;loading.value=true;try{const visits=await medicalApi.visits(patient.patientId);records.value=await Promise.all(visits.map(async item=>{if(item.archiveStatus!=='archived')return item;try{const notebook=await medicalApi.visitNotebook(item.registerId);const exams=notebook.examItems||[];return{...item,checkCount:exams.filter(row=>row.category==='check').length,labCount:exams.filter(row=>row.category==='inspection').length}}catch{return item}}))}finally{loading.value=false}}
function back(){uni.navigateBack({fail:()=>uni.reLaunch({url:'/pages/visits/index'})})}
function openDetail(item:VisitSummary,type:'record'|'check'|'prescription'){if(item.archiveStatus!=='archived'){uni.showToast({title:'病历归档后可查看详情',icon:'none'});return}uni.navigateTo({url:`/pages/record-detail/index?registerId=${item.registerId}&section=${type}`})}
onLoad(()=>{});onShow(load)
</script>
<template><view class="records-page"><view class="header"><view class="back" @tap="back">‹</view><view class="heading"><text>病历与报告</text><text>统一查看历次就诊资料</text></view><view class="hero-art"><view class="paper"/><view class="folder">+</view><view class="leaf">⌯</view></view></view><view class="body"><view class="overview"><view><view class="stat-icon blue">▤</view><view><text>{{records.length}}</text><text>就诊记录</text></view></view><view><view class="stat-icon green">▥</view><view><text>{{archivedCount}}</text><text>已归档病历</text></view></view><view><view class="stat-icon purple">≡</view><view><text>{{diagnosisCount}}</text><text>诊断记录</text></view></view></view><view v-if="loading" class="state">正在加载就诊资料…</view><view v-for="(item,index) in records" :key="item.registerId" class="record-card"><view class="record-icon" :class="tones[index%4]">♡</view><view class="record-content"><view class="record-head"><text>{{item.departmentName||'门诊科室'}}</text><text :class="{archived:item.archiveStatus==='archived'}">● {{item.archiveStatus==='archived'?'已归档':'整理中'}}</text></view><view class="meta"><text>◷ {{(item.visitDate||'').replace('T',' ').slice(0,16)}}</text><text>♧ {{item.physicianName||'门诊医生'}}</text></view><view class="diagnosis"><text>诊断</text><text>{{item.diagnosis||item.preliminaryDiagnosis||(item.archiveStatus==='archived'?'暂无诊断信息':'病历归档后可查看')}}</text></view><view class="links"><text @tap="openDetail(item,'record')">病历详情 ›</text><text @tap="openDetail(item,'check')">检查结果{{item.checkCount?`(${item.checkCount})`:''}} ›</text><text @tap="openDetail(item,'prescription')">处方 ›</text></view></view></view><view v-if="!loading&&!records.length" class="state">暂无就诊资料</view></view></view></template>
<style scoped lang="scss">.records-page{min-height:100vh;background:linear-gradient(180deg,#e7f2ff 0,#f5f8fd 340rpx);color:#102d5d}.header{position:relative;height:285rpx;padding:calc(var(--status-bar-height) + 18rpx) 34rpx 0;box-sizing:border-box;overflow:hidden;background:radial-gradient(circle at 65% 10%,rgba(255,255,255,.95),transparent 48%)}.back{position:relative;z-index:3;width:62rpx;height:62rpx;border-radius:17rpx;display:flex;align-items:center;justify-content:center;background:#fff;box-shadow:0 8rpx 18rpx rgba(42,89,151,.08);color:#2878f5;font-size:52rpx}.heading{position:absolute;z-index:2;left:68rpx;bottom:36rpx;display:flex;flex-direction:column}.heading text:first-child{font-size:42rpx;font-weight:650}.heading text:last-child{margin-top:8rpx;color:#687c9b;font-size:22rpx}.hero-art{position:absolute;right:30rpx;bottom:4rpx;width:245rpx;height:175rpx}.folder{position:absolute;right:23rpx;bottom:8rpx;width:120rpx;height:115rpx;border-radius:12rpx 12rpx 21rpx 21rpx;background:linear-gradient(145deg,#6ab7ff,#3178f4);box-shadow:0 14rpx 25rpx rgba(47,119,232,.2);color:#fff;font-size:65rpx;text-align:center;line-height:112rpx;transform:rotate(2deg)}.paper{position:absolute;right:5rpx;top:5rpx;width:103rpx;height:125rpx;border-radius:9rpx;background:linear-gradient(160deg,#fff,#cfe5ff);transform:rotate(9deg);box-shadow:0 8rpx 18rpx rgba(49,104,177,.12)}.leaf{position:absolute;left:0;bottom:7rpx;color:#42c7a1;font-size:100rpx;transform:rotate(-20deg)}.body{padding:0 24rpx 50rpx}.overview{display:grid;grid-template-columns:repeat(3,1fr);gap:13rpx;margin-top:-5rpx}.overview>view{min-height:105rpx;padding:18rpx 12rpx;display:flex;align-items:center;gap:12rpx;border-radius:22rpx;background:#fff;box-shadow:0 9rpx 24rpx rgba(40,91,159,.08)}.stat-icon{width:55rpx;height:55rpx;flex:none;border-radius:18rpx;display:flex;align-items:center;justify-content:center;color:#fff;font-size:25rpx;box-shadow:0 7rpx 15rpx rgba(44,109,206,.2)}.blue{background:linear-gradient(145deg,#63b5ff,#286cf4)}.green{background:linear-gradient(145deg,#64dcc9,#16b59c)}.purple{background:linear-gradient(145deg,#b28cff,#764cf1)}.orange{background:linear-gradient(145deg,#ffc15a,#ff902b)}.overview>view>view:last-child{display:flex;flex-direction:column}.overview>view>view:last-child text:first-child{color:#2477f5;font-size:31rpx;font-weight:650}.overview>view:nth-child(2)>view:last-child text:first-child{color:#16ad92}.overview>view:nth-child(3)>view:last-child text:first-child{color:#8059ef}.overview>view>view:last-child text:last-child{margin-top:3rpx;color:#7b899f;font-size:17rpx;white-space:nowrap}.record-card{margin-top:17rpx;padding:23rpx;display:flex;gap:17rpx;border:1rpx solid #eaf0f8;border-radius:25rpx;background:#fff;box-shadow:0 9rpx 25rpx rgba(40,91,159,.065)}.record-icon{width:64rpx;height:64rpx;flex:none;border-radius:21rpx;display:flex;align-items:center;justify-content:center;color:#fff;font-size:33rpx;box-shadow:0 8rpx 18rpx rgba(45,104,197,.2)}.record-content{flex:1;min-width:0}.record-head{display:flex;align-items:center;justify-content:space-between}.record-head text:first-child{font-size:27rpx;font-weight:650}.record-head text:last-child{color:#16ac8c;font-size:18rpx}.record-head text:last-child.archived{color:#8491a6}.meta{display:flex;gap:12rpx;margin-top:7rpx;color:#8290a5;font-size:18rpx}.diagnosis{margin-top:14rpx;padding:13rpx 15rpx;border-radius:13rpx;display:flex;align-items:center;background:#f4f8fd}.diagnosis text:first-child{padding:5rpx 10rpx;border-radius:8rpx;background:#e5f1ff;color:#2878ff;font-size:17rpx}.diagnosis text:last-child{margin-left:13rpx;color:#53637d;font-size:19rpx}.links{display:flex;gap:28rpx;margin-top:15rpx;color:#2878ff;font-size:18rpx}.state{margin-top:20rpx;padding:75rpx 20rpx;border-radius:25rpx;background:#fff;text-align:center;color:#8b97a9;font-size:22rpx}</style>
